#include <cstdio>    // printf()
#include <cstdlib>   // atoi()
#include <mutex>
#include <unistd.h>  // sleep()

std::mutex m;
int load_shared_resource(); // Guarded by mutex 'm'

// Some time-intensive computation.
void do_expensive_work(int value, FILE *fd) {
  char buf[4] = "";
  std::fgets(buf, sizeof(buf), fd);
  int sum = value + std::atoi(buf);
  std::printf("value + line: %d\n", sum);
}

void worker_thread(FILE *fd) {
  std::scoped_lock guard(m);
  int value = load_shared_resource();
  // Mutex 'm' could have been released here.
  do_expensive_work(value, fd);
} // Mutex 'm' only released here, after 'do_expensive_work' is returned.

compliant:
#include <pthread.h>
#include <stdio.h>

pthread_mutex_t m;
int shared_resource;

// COMPLIANT: No blocking functions in critical section
void compliant_no_blocking() {
    int temp_value;
    pthread_mutex_lock(&m);
    temp_value = shared_resource;
    shared_resource = temp_value + 1;
    pthread_mutex_unlock(&m);
    // Blocking functions called after unlock - this is OK
    printf("Updated value: %d\n", temp_value + 1);
}

// COMPLIANT: Minimal critical section
void compliant_minimal_critical(FILE* fp) {
    int local_value;
    pthread_mutex_lock(&m);
    local_value = shared_resource;
    pthread_mutex_unlock(&m);

    // Expensive work done outside critical section
    printf("Processing value: %d\n", local_value);
    char buffer[256];
    fgets(buffer, sizeof(buffer), fp);
    int converted = atoi(buffer);

    // Update with new value
    pthread_mutex_lock(&m);
    shared_resource = local_value + converted;
    pthread_mutex_unlock(&m);
}
